/**
 * Expand patristic writings with full chapter coverage.
 * Adds missing sections to already-seeded writings.
 * Run: node scripts/seed-patristic-full.mjs
 */

import Anthropic from '@anthropic-ai/sdk'
import { createClient } from '@supabase/supabase-js'
import * as dotenv from 'dotenv'
import { fileURLToPath } from 'url'
import { dirname, join } from 'path'

const __dirname = dirname(fileURLToPath(import.meta.url))
dotenv.config({ path: join(__dirname, '..', '.env.local') })

const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY })
const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY)

// ── Athanasius: On the Incarnation — all 57 chapters ──────────────────────────
const ATHANASIUS_SECTIONS = [
  { number: 1,  title: 'Preface — The Purpose of This Work',              prompt: 'Write Athanasius On the Incarnation ch. 1: the preface. He has already written "Against the Pagans" to show paganism is wrong. Now he writes to show the Incarnation of the Word — how he took a human body and appeared among men. The knowledge of divine things requires divine grace and a holy life.' },
  { number: 2,  title: 'Creation — God Made All Things Through His Word',  prompt: 'Write Athanasius On the Incarnation ch. 2: God created the universe not from pre-existent matter but from nothing — out of non-existence into existence — through his Word. This refutes the philosophers (matter is eternal) and the Gnostics (the Demiurge). God is good, and a good God would create beings who participate in his goodness.' },
  { number: 3,  title: 'The Making of Humanity — The Image of God',        prompt: 'Write Athanasius On the Incarnation ch. 3: God made humankind uniquely in his own image through his Word. He gave humans a participation in his own rational nature. He also gave a special gift: if they kept the commandment and remained good, they would live the life of Paradise without sorrow, care, or pain, and after death they would live with the angels in heaven.' },
  { number: 4,  title: 'The Threat of Death — "You Shall Surely Die"',     prompt: 'Write Athanasius On the Incarnation ch. 4: God foreknew that humans would sin, but permitted it so they might be free. He gave them a law: "In the day you transgress, you shall die." Death here means not merely physical dissolution but remaining in it — corruption, the reversal of being toward non-being.' },
  { number: 5,  title: 'The Fall — Humans Turn from God to Non-Being',     prompt: 'Write Athanasius On the Incarnation ch. 5: human beings disobeyed. They devised evil. They turned from contemplation of God to contemplation of themselves. In turning away from God who IS, they moved toward non-being. Corruption came upon them. Death spread and held dominion.' },
  { number: 6,  title: 'The Divine Dilemma — What Was God to Do?',         prompt: 'Write Athanasius On the Incarnation ch. 6: what ought God to have done? Option 1: Repentance alone — but this does not satisfy God\'s truthfulness (he had threatened death). Option 2: Do nothing — but this is unworthy of God\'s goodness. Option 3: Simply bring them back into existence — but the corruption already attached would remain.' },
  { number: 7,  title: 'Only the Word Could Restore What He Had Made',     prompt: 'Write Athanasius On the Incarnation ch. 7: only the Word who had made humanity from the beginning could recreate it. No one else was able to recreate what had once been rational and partaker of the Word. He alone, being the image of the Father, could create anew in humanity the image.' },
  { number: 8,  title: 'The Word Takes a Body — The Logic of the Incarnation', prompt: 'Write Athanasius On the Incarnation ch. 8: the Word took a human body — not for his own need but for ours. A body capable of dying. He offered it to death in the stead of all. By dying in a body, he could put an end to corruption in all men. He surrendered his body to death, offering it to the Father.' },
  { number: 9,  title: 'Death Is Absorbed — The Word\'s Offering',         prompt: 'Write Athanasius On the Incarnation ch. 9: since all were under the sentence of death, he took a body capable of dying, so that by offering it to death he might put an end to the law of corruption. For the death of his body was sufficient — since it was the body of the Life itself — to abolish corruption in all.' },
  { number: 10, title: 'Why the Word Did Not Simply Command Incorruption',  prompt: 'Write Athanasius On the Incarnation ch. 10: why did the Word not simply command corruption to stop? Because a mere command would not satisfy justice. The law said "you shall die." That had to be fulfilled. Moreover, a mere word would not be convincing to men — they needed the visible proof of a resurrection.' },
  { number: 11, title: 'The Body He Took — Pure, Holy, Untainted',         prompt: 'Write Athanasius On the Incarnation ch. 11: the body the Word took was real, not illusory — against the Docetists. It was without blemish or sin, born of a virgin so as not to be under Adam\'s condemnation. Being a human body, it was mortal; but being united to the Word, it became immortality-bearing.' },
  { number: 12, title: 'The Birth from the Virgin',                         prompt: 'Write Athanasius On the Incarnation ch. 12: why was the Word born of a virgin specifically? So that the body would be holy and undefiled — not implicated in human corruption inherited from Adam. He took a human body from the Virgin Mary so as to offer it for all and abolish corruption for all.' },
  { number: 13, title: 'The Word Fills the Universe While Dwelling in the Body', prompt: 'Write Athanasius On the Incarnation ch. 13: the Word was not confined to the body — he continued to fill the universe, govern all creation, be present in the Father, and move all things, while also dwelling in the body. He was not diminished by taking a body, as a sunbeam is not diminished by touching earth.' },
  { number: 14, title: 'How the Word Used the Body as an Instrument',      prompt: 'Write Athanasius On the Incarnation ch. 14: he used the body as an instrument. The body was the medium through which he revealed himself to human senses — for humans, distracted by visible things, could not perceive him in his divine invisibility. So he clothed himself in a body so they might see the Creator through the creation.' },
  { number: 15, title: 'The Works of the Incarnate Word — Miracles',       prompt: 'Write Athanasius On the Incarnation ch. 15: the works of the Incarnate Word. He healed the sick, cleansed lepers, gave sight to the blind, raised the dead. By these works he showed that he was not merely a man but the Son of God. The works showed his divine power over nature.' },
  { number: 16, title: 'Why He Did Not Prevent His Own Death',             prompt: 'Write Athanasius On the Incarnation ch. 16: why did he not prevent his death by means of his divine power? Because the purpose of his coming was precisely to die — to take death upon himself. To flee death would be to contradict the purpose of the Incarnation. He came to taste death for all.' },
  { number: 17, title: 'The Death He Died — Why Not a Private Death?',    prompt: 'Write Athanasius On the Incarnation ch. 17: why did he not die privately, or of illness, or in a dignified way? He had to die by a death that was put upon him from outside, not chosen by himself — to show that he was not dying from necessity or weakness but voluntarily. He waited for others to kill him.' },
  { number: 18, title: 'Why the Cross? — The Outstretched Arms',          prompt: 'Write Athanasius On the Incarnation ch. 18: why crucifixion specifically? First, he had to be raised up — to purify the air, which is between earth and heaven. Second, on the cross he spread out his arms to embrace both Jews and Gentiles and draw all to himself. The cross is the symbol of his universal kingship.' },
  { number: 19, title: 'The Cross — Not Weakness but Power',              prompt: 'Write Athanasius On the Incarnation ch. 19: the cross is not weakness — it is the sign of the conqueror. He came to conquer death, and the manner of his dying showed his power over it. A king does not flee from enemies — he faces them. Christ faced death on the cross and by dying conquered it.' },
  { number: 20, title: 'He Died as He Willed — Commanding His Own Death', prompt: 'Write Athanasius On the Incarnation ch. 20: a proof of his sovereignty over death: he died when he chose and how he chose. "Father, into your hands I commit my spirit" — he gave up the ghost at will. Others die when they must; he died when he decided. This itself shows his lordship over death.' },
  { number: 21, title: 'The Resurrection — The Proof Above All Proofs',   prompt: 'Write Athanasius On the Incarnation ch. 21: the resurrection. If Christ had only died and not risen, one might question whether his death had accomplished anything. But he rose. The resurrection is the proof that death has been conquered, that corruption has been abolished, that the body need not remain in death.' },
  { number: 22, title: 'Proofs of the Resurrection — His Works Continue', prompt: 'Write Athanasius On the Incarnation ch. 22: the proof that he rose is visible in his ongoing works. Men and women, inspired by him, scorn death. Virgins maintain their chastity. Men and women embrace poverty, exile, and hardship for his name. Would they do this for a dead man? No — he must be alive.' },
  { number: 23, title: 'The Demons Are Driven Out in His Name',           prompt: 'Write Athanasius On the Incarnation ch. 23: another proof — demons are cast out in his name. The gods of the pagans are still honored in their cities, but they cannot cast out demons. Christ, whom the pagans call dead, drives out demons by his name alone. This proves his resurrection and divine power.' },
  { number: 24, title: 'Death Loses Its Terror Among Christians',         prompt: 'Write Athanasius On the Incarnation ch. 24: before Christ, everyone feared death. Now, the children of the Church scorn death. Virgins run to it; young men present themselves for martyrdom. This change is unprecedented. It would be impossible if Christ had not actually conquered death and risen.' },
  { number: 25, title: 'The Universal Spread of the Faith',               prompt: 'Write Athanasius On the Incarnation ch. 25: the gospel has spread everywhere — to barbarians, Scythians, Ethiopians, Persians. Every language group, every culture, worships Christ. No philosopher, no king, no ruler has achieved this. Plato is read only by educated Greeks; Christ is worshipped by peasants and kings alike across the entire world.' },
  { number: 26, title: 'The Overthrow of Idolatry',                      prompt: 'Write Athanasius On the Incarnation ch. 26: the idols are being overthrown. The oracles have fallen silent. The shrines are deserted. Everywhere men are abandoning the worship of demons and turning to Christ. This is the work of no dead man — only of One who is truly alive and truly God.' },
  { number: 27, title: 'Summary of the Argument So Far',                  prompt: 'Write Athanasius On the Incarnation ch. 27: summary. The Word of God took a body; by his death on the cross he abolished corruption and death; by his resurrection he proved his power over death; by his ongoing works — the spread of the faith, the overthrow of idols, the casting out of demons — he proves that he is risen and alive.' },
  { number: 28, title: 'Against the Jews — Introduction',                 prompt: 'Write Athanasius On the Incarnation ch. 28: now addressing the Jews. They say Christ is not the One spoken of in Scripture. But their own prophets predicted everything about him: the virgin birth, the ministry, the suffering, the death, the resurrection. Athanasius will go through the prophecies in order.' },
  { number: 29, title: 'The Prophecy of Isaiah — "A Virgin Shall Conceive"', prompt: 'Write Athanasius On the Incarnation ch. 29: Isaiah 7:14 — "Behold, a virgin shall conceive and bear a son, and you shall call his name Emmanuel." This was fulfilled in the birth of Christ from the Virgin Mary. The Jews try to read "young woman" but the word is used in context of a miraculous sign.' },
  { number: 30, title: 'The Prophecy of Isaiah — "God With Us" and "Born in Bethlehem"', prompt: 'Write Athanasius On the Incarnation ch. 30: "Emmanuel" means "God with us" — fulfilled in the Incarnation. Micah 5:2: "But you, Bethlehem Ephrathah... from you shall come forth for me one who is to be ruler in Israel, whose origin is from of old, from ancient days." This was fulfilled at the birth of Christ in Bethlehem.' },
  { number: 31, title: 'The Prophecy of Daniel — The Seventy Weeks',     prompt: 'Write Athanasius On the Incarnation ch. 31: Daniel 9:24-27 — the seventy weeks prophecy. "Seventy weeks are decreed... to anoint a most holy place." The time has been fulfilled. The prophecy points to the arrival of Christ. Jerusalem has fallen; sacrifice has ceased. The prophecy was fulfilled in the time of Augustus and Tiberius.' },
  { number: 32, title: 'The Prophecy of the Psalms — "My Heart Overflows"', prompt: 'Write Athanasius On the Incarnation ch. 32: Psalm 45 — "My heart overflows with a goodly theme; I address my verses to the king." The Psalm speaks of a king fairer than the sons of men who is anointed with the oil of gladness above his fellows. This is Christ, anointed with the Holy Spirit above all.' },
  { number: 33, title: 'The Prophecy of Isaiah — The Suffering Servant', prompt: 'Write Athanasius On the Incarnation ch. 33: Isaiah 53 — "He was wounded for our transgressions; he was crushed for our iniquities." This describes the passion of Christ with extraordinary precision — borne before the crucifixion by seven hundred years. He bore our griefs, was led like a lamb to slaughter, made intercession for transgressors.' },
  { number: 34, title: 'The Nations Shall Come — "Ask of Me the Nations"', prompt: 'Write Athanasius On the Incarnation ch. 34: Psalm 2:8 — "Ask of me, and I will make the nations your heritage, and the ends of the earth your possession." This is fulfilled: the nations have come to Christ. The Gentiles have abandoned their idols. This was spoken of no other — only of Christ.' },
  { number: 35, title: 'Why the Jews Do Not Believe — Hardness of Heart', prompt: 'Write Athanasius On the Incarnation ch. 35: why do the Jews not believe, when their own scriptures so clearly predict Christ? Because their hearts are hardened, as Moses and the prophets predicted. They read the Scripture but cannot see. The veil remains over their hearts when they read Moses. But when anyone turns to the Lord, the veil is lifted.' },
  { number: 36, title: 'Against the Greeks — Foolishness of the Cross',  prompt: 'Write Athanasius On the Incarnation ch. 36: now addressing the Greeks (pagans). They mock the cross as foolish. But what is truly foolish — to say God became man, or to say the eternal uncreated has produced the creation by chance? The cross is offensive only to those who cannot see its necessity.' },
  { number: 37, title: 'The Greek Myths — Gods Who Suffered and Died',    prompt: 'Write Athanasius On the Incarnation ch. 37: the Greeks themselves have myths of gods who suffered, were born, and died — Dionysus, Prometheus, Kronos. They do not call these myths foolish. Why then do they mock when the true God truly suffers and truly dies for the salvation of humanity?' },
  { number: 38, title: 'The Philosophers\' Own Teaching About the Logos', prompt: 'Write Athanasius On the Incarnation ch. 38: the Greek philosophers themselves spoke of a divine Logos (Reason) that pervades and governs the universe. Plato and Heraclitus both gestured at this. But they arrived at the idea of the Logos theoretically without knowing how he could become known. The Christians say: the Logos became flesh — that is how he made himself known.' },
  { number: 39, title: 'Why the Word Did Not Take a More Glorious Body',  prompt: 'Write Athanasius On the Incarnation ch. 39: the Greeks complain — why did he not take a more glorious body, a beautiful or powerful one? Because the purpose was not display but salvation. He took an ordinary human body so that all humans could identify with it, so that the medicine could reach all.' },
  { number: 40, title: 'Why He Did Not Appear Somewhere Else — Not in the Desert', prompt: 'Write Athanasius On the Incarnation ch. 40: why did he not appear alone in the desert? Because he came to save all humanity, not just a few philosophers. He appeared publicly, in cities, in the midst of human life, so that his works might be visible to all and his resurrection might be witnessed.' },
  { number: 41, title: 'The Divine Manifestation — He Revealed the Father', prompt: 'Write Athanasius On the Incarnation ch. 41: by his works Christ manifested the Father. The invisible God made himself known through the visible Word made flesh. Just as a good teacher adapts his method to his pupils, the Word adapted his self-revelation to human capacity — through a human body, visible, tangible.' },
  { number: 42, title: 'The Works of the Incarnate Word Revealed His Divinity', prompt: 'Write Athanasius On the Incarnation ch. 42: the miracles of Christ demonstrated his divine power over all things — over disease, over demons, over death, over nature. These are not the works of a mere man. No man could do these things. They are the works of the Word through whom all things were made.' },
  { number: 43, title: 'The Death on the Cross — Its Necessity Defended', prompt: 'Write Athanasius On the Incarnation ch. 43: defending the necessity of the cross. Why not some other death? The cross enabled him to stretch out his hands and draw all people to himself. The cross is a universal symbol — it extends in all directions, binding all things together. It was fitting for the one who holds all things together.' },
  { number: 44, title: 'Why He Died at the Hands of Others and Not Privately', prompt: 'Write Athanasius On the Incarnation ch. 44: why did he not die privately — by fasting or alone? So that no one could say he died from weakness or compulsion. He awaited death at others\' hands so that it would be clear that he had power over death: it was inflicted on him from outside, and he received it voluntarily.' },
  { number: 45, title: 'The Resurrection on the Third Day — Why Three Days?', prompt: 'Write Athanasius On the Incarnation ch. 45: why did he rise on the third day and not immediately? If he had risen immediately, people might not have believed he had truly died. If he had waited longer, people might have forgotten. Three days was sufficient — long enough for death to be real, short enough for the resurrection to be connected to the same person.' },
  { number: 46, title: 'The Evidence of His Ongoing Power — Martyrs',    prompt: 'Write Athanasius On the Incarnation ch. 46: evidence of the resurrection — the martyrs. Men and women go to death joyfully for his name. They cannot be doing this for a dead man. The fact that they die in his name, and die joyfully, proves he is not dead but alive, working in them.' },
  { number: 47, title: 'Chastity and Self-Control Among Christians',      prompt: 'Write Athanasius On the Incarnation ch. 47: another sign — Christian chastity. Before Christ, chastity was rare and philosophy had little success in restraining lust. Now countless virgins and celibate men live in chastity for Christ. This is impossible unless Christ is truly God and truly works in them.' },
  { number: 48, title: 'The Courage of the Martyrs Proves the Resurrection', prompt: 'Write Athanasius On the Incarnation ch. 48: the courage of the martyrs is not natural. Naturally, humans fear death. But Christians approach death with courage and even joy. This is supernatural — it can only be explained by the power of the risen Christ working in them from beyond death.' },
  { number: 49, title: 'Even Women and Children Scorn Death',             prompt: 'Write Athanasius On the Incarnation ch. 49: not only men but women, children, and the uneducated scorn death in Christ\'s name. Plato and the philosophers could persuade only a few educated men to accept death philosophically. Christ persuades all ranks and conditions. This universality proves his divine power.' },
  { number: 50, title: 'The Idols Are Overthrown — Silence of the Oracles', prompt: 'Write Athanasius On the Incarnation ch. 50: the oracles of the pagan gods have fallen silent. Before Christ, the oracle at Delphi was consulted by all nations. Now it is silent. The temples are deserted. Demons no longer dare to speak because Christ has overthrown their power. This is visible, this is historical.' },
  { number: 51, title: 'The Overthrow of the Philosophers and the Rhetoricians', prompt: 'Write Athanasius On the Incarnation ch. 51: Christ has also overthrown the philosophers\' hold on educated culture. Before, Platonism, Stoicism, Epicureanism competed for educated minds. Now, fishermen\'s words have displaced the philosophers\' subtleties everywhere. The simple proclamation of the cross and resurrection has proven more powerful than all philosophical argument.' },
  { number: 52, title: 'How to Know the Word — By Living a Holy Life',   prompt: 'Write Athanasius On the Incarnation ch. 52: to know the divine Word requires a holy life. You cannot perceive God with an impure mind. The way to know the Word is to imitate his virtues — holiness, justice, mercy, truth. Those who live this way will recognize him when he speaks.' },
  { number: 53, title: 'Reading the Scriptures with a Holy Life',         prompt: 'Write Athanasius On the Incarnation ch. 53: to understand the Scriptures properly, one must live a holy life and read them with prayer. He who would understand what the prophets said must be a good person. The mystery of godliness is known by godly living, not by mere intellectual cleverness.' },
  { number: 54, title: 'The Way of Knowledge — Purity and Prayer',       prompt: 'Write Athanasius On the Incarnation ch. 54: the path to knowledge of God is through purity of soul, practice of virtue, and prayer. The mind must be cleansed of earthly things before it can perceive divine things. He who would see God must first be pure in heart, as Christ said: "Blessed are the pure in heart, for they shall see God."' },
  { number: 55, title: 'Christ the Sun of Righteousness',                 prompt: 'Write Athanasius On the Incarnation ch. 55: as the sun must be seen by eyes that face it directly and are healthy, so Christ the Sun of Righteousness must be seen with eyes of the soul that are healthy — free from sin. The impure cannot see the pure. Live purely, and you will see him.' },
  { number: 56, title: 'Conclusion — The Wonder of the Incarnation',      prompt: 'Write Athanasius On the Incarnation ch. 56: the conclusion. The wonder of the Incarnation is that the immeasurable God became measurable; the invisible became visible; the eternal entered time; he who fills the universe was contained in a body. None of this diminished him. He remained what he was while becoming what he was not.' },
  { number: 57, title: 'Final Words — The Greatness of This Mystery',     prompt: 'Write Athanasius On the Incarnation ch. 57: the final chapter. He commends these matters for further study, especially by reading the Scriptures. No single work can exhaust the riches of the Incarnation. Let the reader pursue this further in the Scriptures themselves. For the knowledge of Christ is inexhaustible.' },
]

// ── Justin Martyr: First Apology — all 68 chapters ────────────────────────────
const JUSTIN_SECTIONS = [
  // We already have 1-6, so start from 7
  { number: 7,  title: 'Christians Are Accused Without Investigation',     prompt: 'Write Justin Martyr First Apology ch. 7: Christians are punished for the name alone, without investigation into their deeds. Justin asks: investigate the charges. If we are guilty of crimes, punish us. If we are innocent, reason requires you to let us go. The name "Christian" is not itself a crime.' },
  { number: 8,  title: 'Christians Believe in the Resurrection and Judgment', prompt: 'Write Justin First Apology ch. 8: Christians are not atheists — they believe in God, the Son of God, the prophetic Spirit. They believe in the resurrection and judgment. This belief actually makes them better citizens — they fear the judgment of God more than the judgment of men, so they behave morally.' },
  { number: 9,  title: 'Christians Reject Idols — Not for Lack of Reverence', prompt: 'Write Justin First Apology ch. 9: Christians do not worship idols — not because they lack reverence but because the God who made the universe cannot be contained in temples made with hands, cannot receive what humans make. We give to God what he truly desires: prayer, thanksgiving, and imitation of his goodness.' },
  { number: 10, title: 'The Christian Life — Virtue, Not Vice',            prompt: 'Write Justin First Apology ch. 10: Christian teaching about the way of life. We are taught that God desires righteousness, not sacrifice. He delights in those who imitate his goodness: moderation, justice, love of mankind. We teach these things and we live by them. Our accusers cannot show us to be guilty of evil.' },
  { number: 11, title: 'We Seek a Kingdom — But Not of This World',       prompt: 'Write Justin First Apology ch. 11: when we say we look for a kingdom, we do not mean an earthly kingdom — our accusers think we are seditious. We mean a kingdom with God, as is clear from how we confess Christ and live: we are cheerful even when you execute us, not like men who hope for earthly goods.' },
  { number: 12, title: 'Christian Ethics Produce Good Citizens',           prompt: 'Write Justin First Apology ch. 12: our teachings produce better citizens than any law. We teach that God sees all things; therefore nothing is hidden from him. This makes our people more honest than laws can enforce. We teach that those who do not live righteously and follow Christ will be punished in eternal fire.' },
  { number: 13, title: 'Christian Worship — Prayer and Thanksgiving',     prompt: 'Write Justin First Apology ch. 13: Christians give to God the only worthy worship: rational prayer and thanksgiving for creation, health, and the variety of existence. We do not offer incense or blood — what benefit would God get from these? We praise him through the Word.' },
  { number: 14, title: 'The Teaching of Christ — The Sermon on the Mount', prompt: 'Write Justin First Apology ch. 14: the moral teaching of Jesus. Turn the other cheek. Love your enemies and pray for those who persecute you. Do not swear at all. Share what you have. Do not resist evil with evil. These teachings are verified by the lives of Christians who practice them.' },
  { number: 15, title: 'Chastity and Marriage — Christian Teaching',      prompt: 'Write Justin First Apology ch. 15: Christ\'s teaching on chastity. "Anyone who looks at a woman to lust after her has already committed adultery." We are taught to remain in whatever marriage we were in when we came to faith, unless we discover adultery, and then to remarry is permitted. Many Christians remain unmarried for life.' },
  { number: 16, title: 'Non-Violence — "Love Your Enemies"',              prompt: 'Write Justin First Apology ch. 16: on non-violence. We do not repay evil for evil but turn the other cheek. "Love your enemies and pray for those who mistreat you, that you may be children of your Father who is in heaven." We practice this: we pay taxes, we serve in the army, we obey the authorities — but we will not deny Christ.' },
  { number: 17, title: 'Christians Pay Taxes and Obey Authorities',       prompt: 'Write Justin First Apology ch. 17: Christians obey the civil authorities. Christ himself said "Render to Caesar the things that are Caesar\'s." We pay our taxes and obey the laws in everything that does not require us to deny God. We worship God alone, but in all other things we gladly obey you.' },
  { number: 18, title: 'Immortality of the Soul — The Philosophers Agree', prompt: 'Write Justin First Apology ch. 18: the philosophers themselves taught the immortality of the soul and the punishment of the wicked after death. Plato said the soul survives death. If you accept Plato, you should accept us — we say the same thing with greater authority, for we have the prophets who said it centuries before Plato.' },
  { number: 19, title: 'The Resurrection Is Not Impossible',              prompt: 'Write Justin First Apology ch. 19: the resurrection of the body. You say it is impossible. But consider: God made the body in the first place from nothing. What he made from nothing he can certainly restore. Moreover, if you believe the soul survives death, why not also that the body can be raised?' },
  { number: 20, title: 'The Greeks Have Said the Same Things We Say',     prompt: 'Write Justin First Apology ch. 20: the Greeks themselves have taught what we teach — a single God, the punishment of the wicked, the reward of the virtuous, a divine Reason that pervades the world. Yet they are not persecuted for these doctrines. Why then persecute us for saying the same things with greater certainty?' },
  { number: 21, title: 'The Pagan Myths of Sons of Gods',                 prompt: 'Write Justin First Apology ch. 21: you accept the myths of Hermes, the interpreting Word and son of Zeus. You accept the story of Perseus, born of a virgin. You accept the healing sons of Asclepius. You do not find these incredible. Why then do you find it incredible that Jesus was born of a virgin and is the Son of God?' },
  { number: 22, title: 'Jesus Is Greater Than the Sons of Zeus',          prompt: 'Write Justin First Apology ch. 22: in saying that the Word was born as a man without human intercourse, we say something similar to what you say of Hermes. In saying he healed the lame, the blind, and the dead, we say something like what you say of Asclepius. But we say the truth, not myth.' },
  { number: 23, title: 'The Uniqueness of Christ — Unlike the Myths',     prompt: 'Write Justin First Apology ch. 23: Christ is unlike the mythical sons of Zeus. The sons of Zeus are presented as lovers of pleasure, drunkards, tyrants. Christ is presented as one who was chaste, temperate, the teacher of temperance — and whose life and teaching can be verified by his disciples\' accounts.' },
  { number: 24, title: 'The Injustice of Punishing Only Christians',      prompt: 'Write Justin First Apology ch. 24: it is unjust to punish us for beliefs that you tolerate in others. The philosophers who taught about divine things are not punished. The poets whose myths are far more offensive are not punished. Only Christians are punished. This is irrational — we deserve the same freedom as others, or they deserve the same treatment as us.' },
  { number: 25, title: 'The Silence of the Oracles When Christ Came',    prompt: 'Write Justin First Apology ch. 25: when Christ came, the oracles fell silent. The demons who had spoken through the oracles were put to flight by his name. This is a visible, historical fact. The oracle at Delphi, which had spoken for centuries, fell silent in the time of Christ and has not recovered.' },
  { number: 26, title: 'Heresies — Simon Magus and Marcion',              prompt: 'Write Justin First Apology ch. 26: there are those who call themselves Christians but teach contrary things — Simon of Samaria (Simon Magus), worshipped in Rome as a god; Menander; Marcion who says the God of the OT is different from the Father of Jesus. We are not responsible for these. Do not confuse us with them.' },
  { number: 27, title: 'The Scandal of Exposure of Children',             prompt: 'Write Justin First Apology ch. 27: we do not expose children (a common Roman practice). We teach that to expose a child is to commit murder. Moreover, exposed children often end up in brothels — a scandal. We raise all the children born to us and do not expose them.' },
  { number: 28, title: 'Demons Try to Defame Christians',                 prompt: 'Write Justin First Apology ch. 28: the demons stir up hatred against Christians. They work through wicked men to persecute those who live uprightly. But the demons cannot ultimately prevail. Christ has already triumphed over them. The persecution of Christians is the demons\' last gasp.' },
  { number: 29, title: 'Christian Chastity — A Man Made a Eunuch',       prompt: 'Write Justin First Apology ch. 29: to show that Christian chastity is genuine, Justin cites the case of a Christian in Alexandria who petitioned the governor to be surgically made a eunuch in order to prove beyond doubt that he was not engaging in prostitution. This shows the radical commitment of Christians to purity.' },
  { number: 30, title: 'The Argument from Prophecy — Introduction',       prompt: 'Write Justin First Apology ch. 30: the main proof that Jesus is the Christ: fulfilled prophecy. Prophecies were made hundreds and thousands of years before Christ by men who could not have known what would happen. Their fulfillment proves that the Spirit of God spoke through them. Justin will now go through the specific prophecies.' },
  { number: 31, title: 'Moses and the Prophecy of Genesis 49',            prompt: 'Write Justin First Apology ch. 31: Moses wrote fifteen hundred years before Christ. Genesis 49:10 — "The scepter shall not depart from Judah, nor a ruler\'s staff from between his feet, until tribute comes to him; and to him shall be the obedience of the peoples." This was fulfilled when Herod, a foreigner, became king and Christ, the washing of garments in wine (49:11), came.' },
  { number: 32, title: 'Isaiah\'s Prophecy of the Virgin Birth',          prompt: 'Write Justin First Apology ch. 32: Isaiah 7:14 — "Behold, a virgin shall conceive and bear a son." Isaiah wrote seven hundred years before Christ. This was fulfilled in the birth of Jesus from the Virgin Mary. The Jews try to say the word means "young woman" not "virgin," but the Greek translation of their own scriptures uses "virgin."' },
  { number: 33, title: 'The Prophecy of the Spirit Coming Upon Mary',     prompt: 'Write Justin First Apology ch. 33: the angel Gabriel told Mary: "The Holy Spirit will come upon you, and the power of the Most High will overshadow you; therefore the child to be born will be called holy — the Son of God." This is the Spirit of God, not a physical union as in the myths of Zeus.' },
  { number: 34, title: 'Bethlehem — The Place of Birth Was Prophesied',   prompt: 'Write Justin First Apology ch. 34: Micah prophesied: "But you, O Bethlehem Ephrathah... from you shall come forth for me one who is to be ruler in Israel." Jesus was born in Bethlehem. You can verify this from the census records made under Quirinius, the first governor of Judea.' },
  { number: 35, title: 'Prophecy of the Entry Into Jerusalem on a Donkey', prompt: 'Write Justin First Apology ch. 35: Zechariah 9:9 — "Rejoice greatly, O daughter of Zion! Shout aloud, O daughter of Jerusalem! Behold, your king is coming to you; righteous and having salvation is he, humble and mounted on a donkey." This was fulfilled in Christ\'s entry into Jerusalem on Palm Sunday.' },
  { number: 36, title: 'The Prophets Spoke in the Person of God and Christ', prompt: 'Write Justin First Apology ch. 36: Justin explains how to read the prophetic writings. Sometimes the prophets speak in the person of God; sometimes in the person of Christ; sometimes in their own person. This has confused the readers of Scripture. Understanding this resolves many apparent difficulties.' },
  { number: 37, title: 'Isaiah\'s Prophecy of the Nations Worshipping',   prompt: 'Write Justin First Apology ch. 37: Isaiah 65:1 — "I was ready to be sought by those who did not ask for me; I was ready to be found by those who did not seek me. I said, \'Here I am, here I am,\' to a nation that was not called by my name." This was fulfilled in the Gentiles who came to Christ.' },
  { number: 38, title: 'Psalm 110 — "Sit at My Right Hand"',              prompt: 'Write Justin First Apology ch. 38: Psalm 110 — "The Lord said to my Lord: Sit at my right hand, until I make your enemies your footstool." This was spoken by the Father to the Son. The "Lord" who is David\'s Lord must be greater than David — and is the eternal Word who became Christ.' },
  { number: 39, title: 'The Universal Spread of the Faith — Prophesied', prompt: 'Write Justin First Apology ch. 39: Isaiah 2 — "It shall come to pass in the latter days that the mountain of the house of the Lord shall be established... and all the nations shall flow to it." This has been fulfilled: from Jerusalem the message went out to all nations, and people of every nation now worship the God of Israel through Christ.' },
  { number: 40, title: 'The Psalm of the Passion — "They Divide My Garments"', prompt: 'Write Justin First Apology ch. 40: Psalm 22 — "My God, my God, why have you forsaken me?" This Psalm describes the passion of Christ with extraordinary detail — the mocking, "All who see me mock me; they make mouths at me, they wag their heads"; the casting of lots for his clothing — all fulfilled at the crucifixion.' },
  { number: 41, title: 'The New Sacrifice — The Eucharist Prophesied',   prompt: 'Write Justin First Apology ch. 41: Malachi 1:10-11 — "From the rising of the sun to its setting my name will be great among the nations, and in every place incense will be offered to my name, and a pure offering." This is fulfilled in the Eucharist offered by Christians everywhere — the new sacrifice of the new covenant.' },
  { number: 42, title: 'Christ\'s Sitting at the Right Hand — Not Yet Visible', prompt: 'Write Justin First Apology ch. 42: the prophecy that Christ would sit at the right hand of the Father until his enemies are made his footstool is not yet visibly fulfilled — his enemies still exist. But the invisible fulfillment has begun: the spiritual conquest of the nations is underway. The full visible fulfillment will come at his return.' },
  { number: 43, title: 'Freedom of the Will — We Are Not Fated',          prompt: 'Write Justin First Apology ch. 43: Christians believe in free will, not fate. God has made humans rational and able to choose. He foreknows what choices they will make but does not compel them. If they were compelled, they would not be praiseworthy or blameworthy. The prophets speak of what will happen, not what is fated to happen.' },
  { number: 44, title: 'Plato Learned From Moses',                         prompt: 'Write Justin First Apology ch. 44: Plato\'s teaching that the soul is immortal and that the wicked are punished after death — he took this from Moses. Plato visited Egypt and had access to the writings of Moses. His famous Allegory of the Cave and his teaching about the Form of the Good are ultimately derived from Moses\' teaching.' },
  { number: 45, title: 'The Prophets Spoke Beyond Their Understanding',   prompt: 'Write Justin First Apology ch. 45: the prophets did not always understand what they spoke. The Spirit of God spoke through them about things beyond their knowledge. This is why their prophecies can be so precisely fulfilled — they were not reasoning from present circumstances but speaking what the Spirit gave them.' },
  { number: 46, title: 'Christ and the Logos — Pre-Christian Christians',  prompt: 'Write Justin First Apology ch. 46: all who lived according to the Logos (Reason/Word) are Christians, even if called atheists — like Socrates, Heraclitus, and Abraham. The Logos is one; those who live according to the whole Logos are Christians. Those who lived before Christ and followed reason as best they could were, in a true sense, living by Christ.' },
  { number: 47, title: 'The Dispersion of the Jews Was Prophesied',       prompt: 'Write Justin First Apology ch. 47: Zechariah and the other prophets predicted that the Jews would be scattered from their land after the coming of Christ. This has been fulfilled: after they crucified Christ and rejected the apostles, Jerusalem was destroyed and the Jews were scattered. The land is now inhabited by other nations.' },
  { number: 48, title: 'The Signs of Christ\'s First Coming — Fulfilled',  prompt: 'Write Justin First Apology ch. 48: all the signs of the first coming of Christ have been fulfilled: born of a virgin, born in Bethlehem, performing miracles, hated and crucified, rising from the dead, ascending to heaven, and being preached to all nations. These are historical facts, not prophecies awaiting fulfillment.' },
  { number: 49, title: 'Isaiah on the Hardness of Israel\'s Heart',       prompt: 'Write Justin First Apology ch. 49: Isaiah 6:9-10 — "Make the heart of this people dull, and their ears heavy, and blind their eyes." Why did God harden Israel? Because they refused to hear the prophets. The hardening is a judgment on their earlier rejection. Yet some from Israel have believed, for Isaiah also says "a remnant will return."' },
  { number: 50, title: 'The Suffering Servant — Isaiah 53 in Full',       prompt: 'Write Justin First Apology ch. 50: Justin quotes Isaiah 53 at length — the Suffering Servant passage. "He was despised and rejected by men; a man of sorrows and acquainted with grief." Justin argues that this was fulfilled in the passion of Christ in every detail. No other figure in history fits this description.' },
  { number: 51, title: 'Isaiah 53 — The Passion Foretold in Detail',      prompt: 'Write Justin First Apology ch. 51: continuing the exposition of Isaiah 53. "He was wounded for our transgressions; he was crushed for our iniquities." The cross as the bearing of our sins. "With his stripes we are healed." "He bore the sin of many and makes intercession for the transgressors" — fulfilled in Christ\'s prayer from the cross.' },
  { number: 52, title: 'The Second Coming — Still to Come',               prompt: 'Write Justin First Apology ch. 52: the second coming is still to come. Zechariah 12:10 — "They will look on me, on him whom they have pierced, and they shall mourn for him, as one mourns for an only child." This will happen at the second coming. The signs of the second coming are: fire, the resurrection, the universal judgment.' },
  { number: 53, title: 'The Prophecies Are Clear — Read Them for Yourself', prompt: 'Write Justin First Apology ch. 53: Justin invites the emperor to read the Scriptures for himself in the library. The Septuagint (Greek translation of the OT) is in the library at Alexandria. Compare the prophecies with the facts of Christ\'s life. The fulfillment is visible to anyone who reads with an open mind.' },
  { number: 54, title: 'The Demons Imitated the Prophecies in Advance',   prompt: 'Write Justin First Apology ch. 54: the demons, who had read the prophecies, tried to discredit them in advance by creating pagan myths that resembled them. The virgin birth of Perseus, the cruciform posture of the winged horse — these were demonic imitations planted to make the true events seem like imitations of myths.' },
  { number: 55, title: 'The Cross Is the Symbol Hidden in All Things',    prompt: 'Write Justin First Apology ch. 55: the cross is the sign of power in the world. Ships sail by a cross (mast + yard). Tools work by a cross shape. The human face at prayer extends the arms in a cross. The Roman military standard is a cross. The cross is the sign of dominion without which nothing can hold together.' },
  { number: 56, title: 'Simon Magus — A Demon Worshipped in Rome',        prompt: 'Write Justin First Apology ch. 56: Simon Magus was a Samaritan sorcerer who came to Rome and was worshipped there as a god — a statue was erected to him on the Tiber island. Justin requests that the emperor investigate and remove this statue. Simon is a servant of demons, not a god.' },
  { number: 57, title: 'Marcion\'s God — A Different God',                prompt: 'Write Justin First Apology ch. 57: Marcion teaches that there is a god above the Creator — the Father of Jesus is different from the God of the Old Testament. This is the teaching of demons. There is only one God. The God who spoke through the prophets is the Father of Jesus Christ. Marcion\'s followers are widespread but teach error.' },
  { number: 58, title: 'The Demons Stir Up Persecution',                  prompt: 'Write Justin First Apology ch. 58: the demons stir up persecution against Christians because Christians expose their deceptions. When Christians preach the Word and people turn from idols, the demons lose their worshippers. The demons then work through rulers and mobs to persecute Christians. But this persecution only increases the faith.' },
  { number: 59, title: 'Plato\'s Timaeus — Borrowed from Moses',          prompt: 'Write Justin First Apology ch. 59: Plato\'s Timaeus, in which he describes creation — "God formed the universe from unformed matter" — is borrowed from Genesis 1: "In the beginning God created the heavens and the earth; the earth was without form." Even Plato\'s "X-shape" of the World Soul is an imperfect reading of Moses\' account of the bronze serpent.' },
  { number: 60, title: 'The Word in the Burning Bush — Pre-Incarnate Appearance', prompt: 'Write Justin First Apology ch. 60: when Moses saw the burning bush and heard "I AM WHO I AM," it was not the Father but the Word (Logos) who appeared. The Father cannot be contained in any place; it was the Son who appears and speaks. This is consistent with John 1: the Word has always been the mediator between God and humanity.' },
  { number: 61, title: 'Baptism — The New Birth of Water and Spirit',     prompt: 'Write Justin First Apology ch. 61: the practice of Christian baptism. Those who are persuaded of the truth are brought to a place where there is water. There they are washed in water in the name of the Father Almighty and of Jesus Christ and of the Holy Spirit. This is the new birth — the washing away of sins committed in ignorance.' },
  { number: 62, title: 'The Demons Imitated Baptism in Their Mysteries',  prompt: 'Write Justin First Apology ch. 62: the demons, learning from the prophets that a washing was coming, introduced washings into their own mystery rites — Mithras, Isis. But their washings are empty. The Christian baptism is the true one, because it is in the name of the true God, and it actually forgives sins.' },
  { number: 63, title: 'The Son of God — Father of All Things',           prompt: 'Write Justin First Apology ch. 63: the Son of God, who is the Word and Wisdom of the Father, is the one through whom all things were made. He is the one who appeared to Moses in the bush and who was with the patriarchs. He took on flesh and became human so as to teach these truths in person.' },
  { number: 64, title: 'The Pagan Imitations of the Trinity',             prompt: 'Write Justin First Apology ch. 64: the demons, knowing of the Trinity from the prophets, created imitations — Jupiter (Father), Mercury/Hermes (Word), and Kore (Spirit or Wisdom). But these are distorted imitations. The true Trinity is the Father, the Word (Jesus Christ), and the Prophetic Spirit.' },
  { number: 65, title: 'The Eucharist — The First Description',           prompt: 'Write Justin First Apology ch. 65: after the baptism of the new believer, he is brought to the assembly. Prayer is offered for him and for all. Then bread, wine, and water are brought. The president of the assembly offers prayers and thanksgivings in the name of the Son and Holy Spirit. The people say Amen. The deacons distribute the eucharisted bread, wine, and water.' },
  { number: 66, title: 'The Eucharist Is Not Common Food',                prompt: 'Write Justin First Apology ch. 66: this food is not common bread and common drink. It is the flesh and blood of Jesus who was made flesh. The Word of God made flesh — Jesus Christ our Savior — commanded his disciples that this bread and wine, blessed by the prayer of the Word, should be his flesh and blood.' },
  { number: 67, title: 'The Sunday Assembly — Order of Worship',          prompt: 'Write Justin First Apology ch. 67: the order of the Sunday assembly. On the day called Sunday, all those who live in cities or in the country gather together. The memoirs of the apostles (Gospels) or the writings of the prophets are read for as long as time permits. The president verbally instructs and exhorts. Then we all rise together and pray. Then bread, wine, and water are brought. The president offers prayers and thanksgivings. The people say Amen. Then the Eucharist is distributed and sent to those absent. Then a collection is taken for the orphans, widows, sick, prisoners, and strangers.' },
  { number: 68, title: 'The Closing Appeal — Investigate and Do Justice',  prompt: 'Write Justin First Apology ch. 68: the closing appeal to the emperor. Justin has made his case. He asks only for justice: investigate the charges against Christians. If we are guilty of the things they say, punish us. If we are innocent, do not punish us for the name alone. Reason requires this. He appended the rescript of Hadrian on the same subject.' },
]

// ── Irenaeus: Against Heresies Book I — full 31 chapters ──────────────────────
const IRENAEUS_SECTIONS = [
  // Already have 1-6
  { number: 7,  title: 'Valentinus Himself — Origin of the System',       prompt: 'Write Irenaeus Against Heresies Book I ch. 7: the origin of the Valentinian system with Valentinus himself. He came to Rome under Hyginus and flourished under Pius. He adapted Pythagorean and Platonic principles to his "gnosis." He first introduced the idea of the Pleroma of thirty Aeons.' },
  { number: 8,  title: 'How They Read Scripture — Twisting the Text',     prompt: 'Write Irenaeus Against Heresies Book I ch. 8: the Valentinians read Scripture by taking verses out of context and fitting them into their pre-existing system. They use "not the whole" — they take a piece from Matthew, a piece from Paul, a piece from the Psalms — and weave them together like a mosaic rearranged from a king into a fox.' },
  { number: 9,  title: 'Their Treatment of the Parables',                 prompt: 'Write Irenaeus Against Heresies Book I ch. 9: the Valentinians interpret the parables of Christ as referring to their Aeons. The lost sheep is Sophia. The prodigal son represents the material man returning to the Demiurge. The woman with ten coins represents Sophia seeking the lost Aeon. Irenaeus shows how arbitrary these interpretations are.' },
  { number: 10, title: 'The Rule of Faith — One God, One Christ, One Spirit', prompt: 'Write Irenaeus Against Heresies Book I ch. 10: the Rule of Faith (Regula Fidei) which the Church holds everywhere. One God, the Father Almighty, maker of heaven and earth. One Christ Jesus, the Son of God, incarnate for our salvation. The Holy Spirit who proclaimed through the prophets. The Church scattered throughout the whole world holds this one faith without variation.' },
  { number: 11, title: 'Valentinus and His Variations — Many Schools',    prompt: 'Write Irenaeus Against Heresies Book I ch. 11: the variations within the Valentinian school — Ptolemy, Heracleon, Marcus, Colorbasus. Each teacher has his own variation on the system. This very plurality of variations shows the system is human invention, not divine revelation. The Church has one teaching; the heretics have as many teachings as teachers.' },
  { number: 12, title: 'The System of Marcus the Magician',               prompt: 'Write Irenaeus Against Heresies Book I ch. 12: Marcus the Magician, a disciple of Valentinus, has an elaborate system based on numbers, letters, and syllables. He claims the Greek alphabet itself reveals the divine mysteries — Alpha through Omega encode the structure of the Pleroma. He uses this to impress credulous followers.' },
  { number: 13, title: 'Marcus\'s Eucharist — A Fake Miracle',            prompt: 'Write Irenaeus Against Heresies Book I ch. 13: Marcus performs a fake Eucharistic miracle. He takes a large cup of wine, speaks his prayer over it, and it turns red — appearing to multiply from a small cup to a large one. Irenaeus suggests he uses chemical tricks. He uses this "miracle" to seduce women into his sect and into immoral relations.' },
  { number: 14, title: 'The Numerology of Marcus — Alpha and Omega',      prompt: 'Write Irenaeus Against Heresies Book I ch. 14: Marcus\'s numerological system. The first Tetrad (four primary Aeons) corresponds to Alpha, Beta, Gamma, Delta. The name Jesus (in Greek) has six letters — corresponding to the six days of creation. He builds an elaborate system in which every biblical number encodes a higher mystery.' },
  { number: 15, title: 'The Alphabetical Sophia of Marcus',               prompt: 'Write Irenaeus Against Heresies Book I ch. 15: Marcus\'s claim that Sophia revealed the alphabet to him. The letters of the Greek alphabet were uttered by the divine Sophia herself in the order of their sounds. This is, Irenaeus notes, pure fantasy — Marcus invents a divine experience to give authority to his speculations.' },
  { number: 16, title: 'Refutation of Marcus by the Numbers',             prompt: 'Write Irenaeus Against Heresies Book I ch. 16: Irenaeus begins to refute Marcus\'s numerology. If the name "Jesus" has six letters, so does the Greek word for "pigeon" (peristera). By Marcus\'s logic, the pigeon would be as divine as Jesus. The method is arbitrary — any number of things can be made to "correspond" to anything.' },
  { number: 17, title: 'The Disciples of Marcus — Their Character',       prompt: 'Write Irenaeus Against Heresies Book I ch. 17: the character of Marcus\'s disciples. They seduce women by flattery and by the pretense of spiritual gifts. They promise that through them women can prophesy. They live immorally, claiming that "spiritual" people are not harmed by bodily acts. Several women in Irenaeus\'s own region in Gaul have been seduced.' },
  { number: 18, title: 'The Variations Among the Valentinians on the Passion', prompt: 'Write Irenaeus Against Heresies Book I ch. 18: the Valentinians disagree among themselves about what the passion of Christ signifies. For some, it represents the passion of Sophia. For others, it represents the experience of the Christ in relation to the cross-shaped boundary of the Pleroma. These disagreements reveal the human origin of the system.' },
  { number: 19, title: 'Their Christology — How They Divide Christ',      prompt: 'Write Irenaeus Against Heresies Book I ch. 19: Valentinian Christology. They say the Christ is a composite being: the spiritual element from the Pleroma, a psychic Christ, a material body provided for appearances only. At the passion, the spiritual Christ withdrew and only the psychic and material parts suffered. This is docetism.' },
  { number: 20, title: 'Their Claim to a Secret Tradition — "Hidden Gnosis"', prompt: 'Write Irenaeus Against Heresies Book I ch. 20: the Valentinians claim to possess a secret tradition handed down from the apostles privately — a tradition not contained in the public scriptures. Irenaeus denies this. The apostles publicly proclaimed everything necessary for salvation. There is no secret tradition hidden from the Church.' },
  { number: 21, title: 'Their Initiatory Rites and Death-Bed Rituals',   prompt: 'Write Irenaeus Against Heresies Book I ch. 21: the various initiatory rites of the Valentinian groups. Some baptize with oil and water, saying certain formulas. Some anoint the dying with oil and water so they can pass through the Archons. Some use bridal chamber rituals. The diversity of their rites reveals they are human inventions.' },
  { number: 22, title: 'The Ophites and Their Teaching About the Serpent', prompt: 'Write Irenaeus Against Heresies Book I ch. 22: the Ophites (Serpent-worshippers). They honor the serpent of Genesis 3 as the agent of gnosis — it was the serpent, they say, who truly revealed knowledge to Adam and Eve. The God who forbade them to eat was ignorant and jealous. The serpent is the hero of Eden.' },
  { number: 23, title: 'Simon Magus — The Father of All Heresies',        prompt: 'Write Irenaeus Against Heresies Book I ch. 23: Simon Magus of Samaria is the father of all heresies. He came from a Samaritan village, was baptized by Philip, and then tried to buy the power of the Spirit from Peter (Acts 8). He claimed to be the Father appearing as the Son, the Son in Samaria, and the Holy Spirit among the Gentiles.' },
  { number: 24, title: 'Menander, Saturninus, and Basilides',             prompt: 'Write Irenaeus Against Heresies Book I ch. 24: the disciples of Simon — Menander, then Saturninus of Antioch and Basilides of Alexandria. Saturninus taught that there are 365 heavens with 365 angels; the God of the Jews is one of the angels; Christ came from the highest Father to overthrow the God of the Jews. Marriage and procreation are of Satan.' },
  { number: 25, title: 'Carpocrates and the Libertine Gnosis',            prompt: 'Write Irenaeus Against Heresies Book I ch. 25: Carpocrates and his son Epiphanes. They teach antinomian libertinism — the soul must experience every possible act before it can be released from the cycle of reincarnation. They use the statement "You will not get out until you have paid the last penny" (Matt. 5:26) to justify moral license.' },
  { number: 26, title: 'Cerinthus and the Ebionites',                    prompt: 'Write Irenaeus Against Heresies Book I ch. 26: Cerinthus, a contemporary of the Apostle John, taught that Jesus was the natural son of Joseph and Mary — an ordinary man — and that the Christ descended on him at baptism as a dove and left before the passion. The Ebionites similarly denied the virgin birth and used only Matthew\'s Gospel.' },
  { number: 27, title: 'Marcion — God and the Demiurge',                 prompt: 'Write Irenaeus Against Heresies Book I ch. 27: Marcion of Pontus, the most dangerous of the heretics. He taught that there are two gods: the Demiurge (Creator, God of the OT — just but not good), and the higher God (Father of Jesus — good but previously unknown). Marcion rejected the entire OT and kept only an edited version of Luke and ten Pauline letters.' },
  { number: 28, title: 'Other Gnostic Groups — A Survey',                prompt: 'Write Irenaeus Against Heresies Book I ch. 28: a survey of other Gnostic groups — the Encratites who forbid marriage, meat, and wine; the followers of Tatian; the Severians; others who combine various elements of the above systems. Irenaeus notes that the groups multiply endlessly, each teacher adding his own speculations.' },
  { number: 29, title: 'The Barbeliotes and Their Mythology',            prompt: 'Write Irenaeus Against Heresies Book I ch. 29: the Barbeliotes, named for Barbelo (the divine Mother/Thought). An elaborate mythology: the perfect Father, then Barbelo (his Thought), then the divine Autogenes (Self-Generated), then the four lights. This is similar to Valentinianism but with different names and a more elaborate feminine principle.' },
  { number: 30, title: 'The Ophite Creation Myth in Detail',              prompt: 'Write Irenaeus Against Heresies Book I ch. 30: the Ophite creation myth. Ialdabaoth (the Demiurge/Craftsman) is born from the lower Sophia without the Father\'s knowledge. He is lion-headed. He creates the seven heavens. He says "I am a jealous God; there is no God beside me" — not knowing of the higher God above him. He puts the divine spark into Adam.' },
  { number: 31, title: 'Conclusion of Book I — What Has Been Exposed',   prompt: 'Write Irenaeus Against Heresies Book I ch. 31 (conclusion): Irenaeus has now exposed the Valentinian system in all its complexity and the other Gnostic systems. They are like a many-headed Hydra. Every time one head is cut off, another appears. But the Church stands firm in the one Rule of Faith received from the apostles. In the next books he will refute these systems by Scripture and reason.' },
]

async function generateSection(writingTitle, fatherName, section) {
  const message = await anthropic.messages.create({
    model: 'claude-sonnet-4-6',
    max_tokens: 1500,
    messages: [
      {
        role: 'user',
        content: `You are generating content for a Bible study app's Church Fathers section.

Writing: "${writingTitle}" by ${fatherName}
Section ${section.number}: "${section.title}"

Task: ${section.prompt}

Write 350-500 words of flowing prose that faithfully represents the actual content of this section of the text. Use the style of the Roberts-Donaldson translation for ANF texts. Include direct quotations where they are famous or significant. Start directly with the content — no title or header.`,
      },
    ],
  })
  return message.content[0].type === 'text' ? message.content[0].text.trim() : ''
}

async function seedSections(slug, title, fatherName, sections) {
  console.log(`\n── ${title} ──`)

  const { data: writing } = await supabase
    .from('patristic_writings')
    .select('id, total_sections')
    .eq('slug', slug)
    .single()

  if (!writing) {
    console.log(`  ✗ Writing "${slug}" not found in DB — run seed-patristic.mjs first`)
    return
  }

  const { data: existing } = await supabase
    .from('patristic_sections')
    .select('section_number')
    .eq('writing_id', writing.id)

  const seededNums = new Set((existing ?? []).map((s) => s.section_number))
  const todo = sections.filter((s) => !seededNums.has(s.number))

  if (todo.length === 0) {
    console.log(`  All ${sections.length} sections already seeded`)
    return
  }

  console.log(`  ${seededNums.size} already done, generating ${todo.length} new sections...`)

  for (const section of todo) {
    process.stdout.write(`  [${section.number}] ${section.title}... `)
    try {
      const content = await generateSection(title, fatherName, section)
      const { error } = await supabase.from('patristic_sections').insert({
        writing_id: writing.id,
        section_number: section.number,
        title: section.title,
        content,
      })
      if (error) throw error
      console.log('✓')
      await new Promise((r) => setTimeout(r, 500))
    } catch (err) {
      console.log(`✗ ${err.message}`)
    }
  }

  // Update total_sections count
  const newTotal = (seededNums.size) + todo.length
  await supabase.from('patristic_writings').update({ total_sections: newTotal }).eq('id', writing.id)
  console.log(`  Done — ${newTotal} total sections`)
}

async function main() {
  console.log('Expanding patristic writings with full chapter coverage...')

  await seedSections('on-the-incarnation',          'On the Incarnation',          'Athanasius of Alexandria', ATHANASIUS_SECTIONS)
  await seedSections('justin-first-apology',         'First Apology',               'Justin Martyr',            JUSTIN_SECTIONS)
  await seedSections('irenaeus-against-heresies-1',  'Against Heresies — Book I',   'Irenaeus of Lyon',         IRENAEUS_SECTIONS)

  console.log('\n\nAll done!')
}

main().catch(console.error)
